import {
  GIT_COMMIT_FIRST_LINE_LIMIT,
  PROJECT_CLI,
  PROJECT_NAME_DISPLAY,
} from "#src/constants.js";

// These are template strings for generated hook scripts.
// They are written to disk as standalone Node.js scripts, not executed in this process.
// The use of execSync in templates is intentional for git hook runners.

export const RUNNER_TEMPLATE = `#!/bin/sh
# ${PROJECT_NAME_DISPLAY} pre-commit hook runner — Auto-generated by ${PROJECT_CLI} init
node --input-type=module << 'HOOK_SCRIPT'
import { execFileSync } from 'child_process';

const hooks = {{HOOKS_JSON}};

function getStagedFiles(filter) {
  try {
    const output = execFileSync('git', ['diff', '--cached', '--name-only', '--diff-filter=ACMR'], { encoding: 'utf-8' });
    const files = output.trim().split('\\n').filter(Boolean);
    if (!filter) return files;
    const re = new RegExp(filter.replace(/\\*\\*/g, '.*').replace(/\\*/g, '[^/]*'));
    return files.filter(f => re.test(f));
  } catch { return []; }
}

let exitCode = 0;
for (const hook of hooks) {
  const files = getStagedFiles(hook.stagedFilter);
  if (files.length === 0) continue;
  console.log(\`Running \${hook.name}...\`);
  const [bin, ...baseArgs] = hook.command.split(/\\s+/);
  const args = hook.passFiles === false ? baseArgs : [...baseArgs, ...files];
  try {
    execFileSync(bin, args, { stdio: 'inherit' });
    if (hook.modifiesFiles) {
      execFileSync('git', ['add', ...files], { stdio: 'inherit' });
    }
  } catch (e) {
    console.error(\`\${hook.name} failed\`);
    exitCode = 1;
  }
}
process.exit(exitCode);
HOOK_SCRIPT
`;

export const SECRET_SCAN_TEMPLATE = `#!/usr/bin/env node
// ${PROJECT_NAME_DISPLAY} secret scanner
import fs from 'fs';

const PATTERNS = [
  /(?:api[_-]?key|apikey)\\s*[:=]\\s*['"][^'"]{8,}/i,
  /(?:secret|password|passwd|pwd)\\s*[:=]\\s*['"][^'"]{8,}/i,
  /(?:token|bearer)\\s*[:=]\\s*['"][^'"]{8,}/i,
  /-----BEGIN (?:RSA |EC |DSA )?PRIVATE KEY-----/,
  /ghp_[a-zA-Z0-9]{36}/,
  /sk-[a-zA-Z0-9]{32,}/,
];
const FALSE_POS = /['"](?:your-|\\\\*\\$\\{|process\\.env|os\\.environ)/;
const EXCLUDED = [/tests?\\//, /\\.test\\.[jt]sx?$/, /\\.spec\\.[jt]sx?$/, /__tests__\\//, /\\/references\\//];
const files = process.argv.slice(2).filter(f => !EXCLUDED.some(p => p.test(f)));
let found = false;
for (const file of files) {
  try {
    const content = fs.readFileSync(file, 'utf-8');
    const lines = content.split('\\n');
    for (const pattern of PATTERNS) {
      for (const line of lines) {
        if (pattern.test(line) && !FALSE_POS.test(line)) {
          console.error(\`Potential secret found in \${file}\`);
          found = true;
          break;
        }
      }
      if (found) break;
    }
  } catch {}
}
if (found) process.exit(1);
`;

